    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_namespace_path:Products.A10nBlueprintEngine.Features.TwoLayerArchitecture.two_layers_only:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_single_block_form:Products.A10nBlueprintEngine.Features.TwoLayerArchitecture.two_layers_only:must
