  // ── store-suffix-mismatch ──────────────────────────────────────────────────

  describe("store directory suffix (namespace === path enforcement)", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T006.T006_30
    it("valid — file-store component in *-file-store directory — no diagnostic", async () => {
      await ruleTester
        .expect({
          "main.tsp": `import "./state/components/task-file-store/main.tsp";`,
          "state/components/task-file-store/main.tsp": `
            using State;
            @component(#{ type: ComponentType.Store })
            @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
            namespace Components.TaskFileStore;
          `,
        })
        .toBeValid();
    });

    it("invalid — file-store component (TaskFileStore) in *-store directory — namespace-path mismatch", async () => {
      await ruleTester
        .expect({
          "main.tsp": `import "./state/components/task-store/main.tsp";`,
          "state/components/task-store/main.tsp": `
            using State;
            @component(#{ type: ComponentType.Store })
            @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
            namespace Components.TaskFileStore;
          `,
        })
        .toEmitDiagnostics([
          {
            code: "@a10n/blueprint-typespec/namespace-path",
            message: /task-file-store/,
          },
        ]);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T006.T006_31
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_namespace_path:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.suffix_file_store:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_single_block_form:Products.A10nBlueprintEngine.Features.FileStoreAuthoring.suffix_file_store:must
    it("invalid — @storage component in directory not ending in -file-store — suffix-file-store diagnostic", async () => {
      await ruleTester
        .expect({
          "main.tsp": `import "./state/components/my-store/main.tsp";`,
          "state/components/my-store/main.tsp": `
            using State;
            @component(#{ type: ComponentType.Store })
            @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
            namespace Components.MyStore;
          `,
        })
        .toEmitDiagnostics([
          {
            code: "@a10n/blueprint-typespec/namespace-path",
            message: /must be declared in a directory ending in `-file-store`/,
          },
          {
            code: "@a10n/blueprint-typespec/namespace-path",
            message: /must end in `FileStore`/,
          },
        ]);
    });

    it("valid — @storage component in *-file-store/ named *FileStore — no diagnostic", async () => {
      await ruleTester
        .expect({
          "main.tsp": `import "./state/components/my-file-store/main.tsp";`,
          "state/components/my-file-store/main.tsp": `
            using State;
            @component(#{ type: ComponentType.Store })
            @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
            namespace Components.MyFileStore;
          `,
        })
        .toBeValid();
    });

    it("invalid — @component(Store) without @storage or DBML — store-type-undeclared", async () => {
      await ruleTester
        .expect({
          "main.tsp": `import "./state/components/my-store/main.tsp";`,
          "state/components/my-store/main.tsp": `
            using State;
            @component(#{ type: ComponentType.Store })
            namespace Components.MyStore;
          `,
        })
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/namespace-path",
          message: /must declare its store type/,
        });
    });

    it("valid — relational @component(Store) with DBML in *-relational-store/ named *RelationalStore — no diagnostic", async () => {
      await ruleTester
        .expect({
          "main.tsp": `import "./state/components/my-relational-store/main.tsp";`,
          "state/components/my-relational-store/main.tsp": `
            using State;
            @component(#{ type: ComponentType.Store })
            namespace Components.MyRelationalStore {
              @TypeSpec.Dbml.table(#{})
              model Row { id: string; }
            }
          `,
        })
        .toBeValid();
    });

    it("invalid — relational @component(Store) in *-store/ named *Store — suffix and namespace diagnostics", async () => {
      // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_namespace_path:Products.A10nBlueprintEngine.Features.RelationalStoreAuthoring.suffix_relational_store:must
      // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_operation_reachability_3:Products.A10nBlueprintEngine.Features.RelationalStoreAuthoring.suffix_relational_store:must
      await ruleTester
        .expect({
          "main.tsp": `import "./state/components/my-store/main.tsp";`,
          "state/components/my-store/main.tsp": `
            using State;
            @component(#{ type: ComponentType.Store })
            namespace Components.MyStore {
              @TypeSpec.Dbml.table(#{})
              model Row { id: string; }
            }
          `,
        })
        .toEmitDiagnostics([
          {
            code: "@a10n/blueprint-typespec/namespace-path",
            message: /must be declared in a directory ending in `-relational-store`/,
          },
          {
            code: "@a10n/blueprint-typespec/namespace-path",
            message: /must end in `RelationalStore`/,
          },
        ]);
    });

    it("valid — relational Store in a *-relational-store directory — no diagnostic", async () => {
      await ruleTester
        .expect({
          "main.tsp": `import "./state/components/task-relational-store/main.tsp";`,
          "state/components/task-relational-store/main.tsp": `
            using State;
            @component(#{ type: ComponentType.Store })
            namespace Components.TaskRelationalStore {
              @TypeSpec.Dbml.table(#{})
              model Row { id: string; }
            }
          `,
        })
        .toBeValid();
    });

    it("invalid — relational Store (TaskRelationalStore) in *-store directory — namespace-path mismatch", async () => {
      await ruleTester
        .expect({
          "main.tsp": `import "./state/components/task-store/main.tsp";`,
          "state/components/task-store/main.tsp": `
            using State;
            @component(#{ type: ComponentType.Store })
            namespace Components.TaskRelationalStore;
          `,
        })
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/namespace-path",
          message: /task-relational-store/,
        });
    });
  });

